const express = require('express');
const session = require('express-session');
const twilio = require('twilio');
const bodyParser = require('body-parser');

const app = express();
const client = twilio('ACCOUNT_SID', 'AUTH_TOKEN');

app.use(session({ secret: 'your-secret-key', cookie: { maxAge: 60000 }, saveUninitialized : false }));
app.use(bodyParser.urlencoded({ extended: false }));

app.get('/login', (req, res) => {
    let authCode = Math.floor(100000 + Math.random() * 900000); // generate a 6-digit code
    req.session.authCode = authCode;
    
    client.messages.create({
        body: `Your verification code is ${authCode}`,
        to: 'user_phone_number', 
        from: 'your_twilio_number' 
    })
    .then(() => res.send('A verification code has been sent to your phone number'))
    .catch(err => res.status(500).send(err));
});

app.post('/verify', (req, res) => {
    if (req.body.code == req.session.authCode) {
        req.session.authenticated = true;
        return res.send('You have successfully authenticated');
    }
    return res.status(403).send('Invalid code. Try again!');
});

app.listen(3000, () => console.log('App is listening on port 3000'));